    38→function formatDuration(startedAt?: string, completedAt?: string): string {
    39→  if (!startedAt) return "--";
    40→  const start = new Date(startedAt).getTime();
    41→  const end = completedAt ? new Date(completedAt).getTime() : Date.now();
    42→  const secs = Math.round((end - start) / 1000);
    43→  if (secs < 60) return `${secs}s`;
    44→  const mins = Math.floor(secs / 60);
    45→  const rem = secs % 60;
    46→  return `${mins}m ${rem}s`;
    47→}
    48→
    49→function truncate(str: string, max: number): string {
    50→  return str.length > max ? str.slice(0, max) + "\u2026" : str;
    51→}
