   153→                />
   154→              </div>
   155→              <div className="space-y-2">
   156→                <Label htmlFor="poll_interval">Poll Interval (seconds)</Label>
   157→                <Input
   158→                  id="poll_interval"
   159→                  type="number"
   160→                  min={60}
   161→                  value={pollInterval}
   162→                  onChange={(e) => setPollInterval(e.target.value)}
   163→                />
   164→              </div>
   165→              <div className="space-y-2">
   166→                <Label htmlFor="version_filter_include">Version Filter — Include (regex, optional)</Label>
   167→                <Input
