   174→                <p className="text-xs text-muted-foreground">Only show/notify versions matching this pattern</p>
   175→              </div>
   176→              <div className="space-y-2">
   177→                <Label htmlFor="version_filter_exclude">Version Filter — Exclude (regex, optional)</Label>
   178→                <Input
