   184→                />
   185→                <p className="text-xs text-muted-foreground">Hide/suppress versions matching this pattern</p>
   186→              </div>
   187→              {(provider === "github" || provider === "gitlab") && (
   188→                <label className="flex items-center gap-2 text-sm text-muted-foreground">
   189→                  <input
