   193→                    className="rounded"
   194→                  />
   195→                  Exclude pre-releases
   196→                </label>
   197→              )}
   198→            </div>
   199→          )}
   200→        </div>
   201→      )}
   202→
   203→      <div className="flex justify-end gap-2">
   204→        <Button type="button" variant="outline" onClick={handleCancel}>Cancel</Button>
   205→        <Button type="submit" disabled={saving}>{saving ? "Saving..." : "Save"}</Button>
   206→      </div>
   207→    </form>
   208→  );
   209→
   210→  // Dialog mode: return form content without Card wrapper
   211→  if (onSuccess) {
   212→    return formContent;
   213→  }
   214→
   215→  // Page mode: wrap in Card
   216→  return (
   217→    <Card className="mx-auto max-w-2xl">
   218→      <CardHeader>
   219→        <CardTitle>{title}</CardTitle>
   220→      </CardHeader>
   221→      <CardContent>
   222→        {formContent}
   223→      </CardContent>
   224→    </Card>
   225→  );
   226→}
