    32→export function formatInterval(seconds: number): string {
    33→  if (seconds < 60) return `${seconds}s`;
    34→  if (seconds < 3600) return `${Math.round(seconds / 60)}m`;
    35→  if (seconds < 86400) return `${(seconds / 3600).toFixed(1)}h`;
    36→  return `${(seconds / 86400).toFixed(1)}d`;
    37→}
