    18→
    19→/* ---------- Inline Add Source Form ---------- */
    20→
    21→function InlineSourceForm({
    22→  projectId,
    23→  onDone,
    24→}: {
    25→  projectId: string;
    26→  onDone: () => void;
    27→}) {
    28→  const [provider, setProvider] = useState("github");
    29→  const [repository, setRepository] = useState("");
    30→  const [pollInterval, setPollInterval] = useState("86400");
    31→  const [versionFilterInclude, setVersionFilterInclude] = useState("");
    32→  const [versionFilterExclude, setVersionFilterExclude] = useState("");
    33→  const [excludePrereleases, setExcludePrereleases] = useState(false);
    34→  const [saving, setSaving] = useState(false);
    35→  const [error, setError] = useState("");
    36→
    37→  const handleAdd = async (e: React.FormEvent) => {
    38→    e.preventDefault();
    39→    if (!repository.trim()) return;
    40→    setSaving(true);
    41→    setError("");
    42→    try {
    43→      const repoError = validateRepository(provider, repository.trim());
    44→      if (repoError) {
    45→        setError(repoError);
    46→        setSaving(false);
    47→        return;
    48→      }
    49→      const res = await sourcesApi.create(projectId, {
    50→        provider,
    51→        repository: repository.trim(),
    52→        poll_interval_seconds: Number(pollInterval) || 86400,
    53→        enabled: true,
    54→        version_filter_include: versionFilterInclude.trim() || undefined,
    55→        version_filter_exclude: versionFilterExclude.trim() || undefined,
    56→        exclude_prereleases: excludePrereleases || undefined,
    57→      });
    58→      if (res.data?.id) sourcesApi.poll(res.data.id).catch(() => {});
    59→      mutate(`project-${projectId}-card-sources`);
    60→      onDone();
    61→    } catch (err: unknown) {
    62→      setError(err instanceof Error ? err.message : "Failed to add source");
    63→    } finally {
    64→      setSaving(false);
    65→    }
    66→  };
    67→
    68→  return (
    69→    <form onSubmit={handleAdd} className="mt-2 rounded-md border p-3 space-y-2" style={{ borderColor: "#e8e8e5", backgroundColor: "#fafaf9" }}>
    70→      {error && <div className="text-[12px] text-red-600">{error}</div>}
    71→      <div className="flex items-center gap-2">
    72→        <select
    73→          value={provider}
    74→          onChange={(e) => setProvider(e.target.value)}
    75→          className="rounded-md border px-2 py-1 text-[12px]"
    76→          style={{ borderColor: "#e8e8e5", fontFamily: "var(--font-dm-sans)" }}
    77→        >
    78→          <option value="github">GitHub</option>
    79→          <option value="dockerhub">Docker Hub</option>
    80→          <option value="ecr-public">ECR Public</option>
    81→        </select>
    82→        <input
    83→          type="text"
    84→          value={repository}
    85→          onChange={(e) => setRepository(e.target.value)}
    86→          placeholder="e.g. ethereum/go-ethereum"
    87→          className="flex-1 rounded-md border px-2 py-1 text-[12px]"
    88→          style={{ borderColor: "#e8e8e5", fontFamily: "'JetBrains Mono', monospace" }}
    89→        />
    90→        <input
    91→          type="number"
    92→          min={60}
    93→          value={pollInterval}
    94→          onChange={(e) => setPollInterval(e.target.value)}
    95→          className="w-20 rounded-md border px-2 py-1 text-[12px]"
    96→          style={{ borderColor: "#e8e8e5" }}
    97→          title="Poll interval (seconds)"
    98→        />
    99→      </div>
   100→      <input
   101→        type="text"
   102→        value={versionFilterInclude}
   103→        onChange={(e) => setVersionFilterInclude(e.target.value)}
   104→        placeholder="Include filter (regex, optional)"
   105→        className="w-full rounded-md border px-2 py-1 text-[12px]"
   106→        style={{ borderColor: "#e8e8e5", fontFamily: "'JetBrains Mono', monospace" }}
   107→      />
   108→      <input
   109→        type="text"
   110→        value={versionFilterExclude}
   111→        onChange={(e) => setVersionFilterExclude(e.target.value)}
   112→        placeholder="Exclude filter (regex, optional)"
   113→        className="w-full rounded-md border px-2 py-1 text-[12px]"
   114→        style={{ borderColor: "#e8e8e5", fontFamily: "'JetBrains Mono', monospace" }}
   115→      />
   116→      {provider === "github" && (
   117→        <label className="flex items-center gap-2 text-[12px] text-[#6b7280]">
   118→          <input
   119→            type="checkbox"
   120→            checked={excludePrereleases}
   121→            onChange={(e) => setExcludePrereleases(e.target.checked)}
   122→            className="rounded"
   123→          />
   124→          Exclude pre-releases
   125→        </label>
   126→      )}
   127→      <div className="flex items-center justify-end gap-2">
   128→        <button
   129→          type="button"
   130→          onClick={onDone}
   131→          className="text-[12px] text-[#9ca3af] hover:text-[#6b7280]"
   132→        >
   133→          Cancel
   134→        </button>
   135→        <button
   136→          type="submit"
