   507→              style={{
   508→                backgroundColor: "#eff6ff",
   509→                fontFamily: "'JetBrains Mono', monospace",
   510→                color: "#1d4ed8",
   511→              }}
   512→            >
   513→              {latestSr.version}
   514→            </span>
   515→            {urgencyStyle && (
   516→              <span
   517→                className="inline-flex items-center rounded-full px-1.5 py-0.5 text-[10px] font-medium leading-none shrink-0"
