   528→              </span>
   529→            )}
   530→          </>
   531→        ) : (
   532→          <span className="text-[12px] italic" style={{ color: "#c4c4c0" }}>
   533→            No analysis
   534→          </span>
   535→        )}
   536→      </span>
   537→
   538→      {/* Arrow */}
